  + foot(3) + '</div>';

const byMember = {};
for (const p of pols) { (byMember[p.member] = byMember[p.member] || []).push(p); }
const tblFor = (nm, rows) => {
  let t = '<div class="ptbl-wrap"><div class="ptbl-head">' + esc(nm) + ' <span class="ptbl-sub">· ' + rows.length + ' policies</span></div><table class="ptbl"><thead><tr><th>Policy no</th><th>Plan</th><th>Type</th><th>Sum assured</th><th>Est. maturity*</th><th>Premium/yr</th><th>Maturity</th><th>Status</th></tr></thead><tbody>';
  for (const p of rows) {
    const planCell = p.planName ? esc(p.planName) : ('Tbl ' + esc(p.tbl) + (p.planConfirmed ? '' : '†'));
    t += '<tr><td class="mono">' + esc(p.policyNo) + '</td><td>' + planCell + '</td><td>' + p.type + '</td><td class="num">' + fmtIN(p.sa) + '</td><td class="num">' + (p.estMaturity ? fmtIN(p.estMaturity) : '—') + '</td><td class="num">' + (p.single ? 'one-time' : fmtIN(p.perYear)) + '</td><td>' + esc(p.matLabel) + '</td><td><span class="pill ' + (p.status === 'Matured' ? 'st-matured' : 'st-inforce') + '">' + p.status + '</span></td></tr>';
  }
  return t + '</tbody></table></div>';
};
const gloss = '<div class="gloss"><h4>How to read this report</h4><p><b>Sum assured</b> — the base cover amount. <b>Est. maturity*</b> — base + illustrated bonus per the CGPE plan library; <b>not guaranteed</b>, actual depends on LIC declared bonuses.</p><p>† — legacy plan table not yet confirmed; a default legacy bonus rate was used. Verify against the policy bond.</p><p><b>In-force</b> — still active. <b>Matured</b> — completed and already paid out. <b>Single</b> — premium paid once.</p></div>';
const detailPages = [];
let cur = '', budget = 30;
for (const nm of Object.keys(byMember)) {
  const rows = byMember[nm];
  if (budget - (rows.length + 3) < 0 && cur) { detailPages.push(cur); cur = ''; budget = 30; }
  cur += tblFor(nm, rows); budget -= rows.length + 3;
}
if (cur) detailPages.push(cur);
